class Solution {
public:
    int searchInsert(vector<int>& nums, int target) {
        int n = nums.size();
        int left = 0, right = n - 1, ans = n; // ans 初值 n：全部元素都小于 target 时插在末尾
        while (left <= right) {
            int mid = ((right - left) >> 1) + left;
            if (target <= nums[mid]) { // 找第一个 >= target 的位置：满足就记下并继续向左
                ans = mid;
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        }
        return ans;
    }
};
